import java.util.Arrays;
public class Main {
    public static void main(String[] args) {
        ChatService cs = new ChatService();
        User a = cs.registerUser("Alice");
        User b = cs.registerUser("Bob");
        User c = cs.registerUser("Charlie");
        ChatRoom g = cs.createGroupChat("Team", a.getId(), Arrays.asList(a.getId(), b.getId(), c.getId()));
        cs.sendMessage(g.getId(), a.getId(), "hi all");
        cs.sendMessage(g.getId(), b.getId(), "hey");
        if (cs.getMessageHistory(g.getId()).size() == 2 && "GROUP".equals(g.getRoomType())) System.out.println("GROUP_OK");
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        ChatService cs = new ChatService();
        User a = cs.registerUser("Alice");
        User b = cs.registerUser("Bob");
        ChatRoom dc = cs.createDirectChat(a.getId(), b.getId());
        cs.sendMessage(dc.getId(), a.getId(), "photo.jpg", Message.MessageType.IMAGE);
        cs.sendMessage(dc.getId(), b.getId(), "doc.pdf", Message.MessageType.FILE);
        java.util.List<Message> hist = cs.getMessageHistory(dc.getId());
        if (hist.get(0).getType() == Message.MessageType.IMAGE
            && hist.get(1).getType() == Message.MessageType.FILE
            && hist.get(0).getDisplayText().startsWith("[Image:")) System.out.println("TYPES_OK");
    }
}

