import java.util.Arrays;
public class Main {
    public static void main(String[] args) {
        ChatService cs = new ChatService();
        User a = cs.registerUser("Alice");
        User b = cs.registerUser("Bob");
        cs.setUserStatus(a.getId(), OnlineStatus.ONLINE);
        cs.setUserStatus(b.getId(), OnlineStatus.ONLINE);
        ChatRoom g = cs.createGroupChat("T", a.getId(), Arrays.asList(a.getId(), b.getId()));
        final int[] count = {0};
        cs.addMessageListener(b.getId(), (msg, room) -> { count[0]++; System.out.println("LIS_FIRED:" + msg.getContent()); });
        cs.sendMessage(g.getId(), a.getId(), "ping");
        if (count[0] == 1) System.out.println("LISTENER_OK");
    }
}
